import { put, call } from '@redux-saga/core/effects';
import { api } from '@semparar/mf-app-user';

import { PointsActions } from '../../ducks/points';
import { eventServerResponse } from '~/constants/functions';

export function* getPointsBalance() {
  try {
    const response: {
      data: {
        data: { points?: number };
        status: {
          returnCode?: number;
          codigoRetorno?: number;
          message?: string;
        };
      };
    } = yield call(api.get, 'fintech/v1/rewardProgram/balance', {});

    const points = response?.data?.data?.points;

    const returnCode = response?.data?.status?.returnCode ?? response?.data?.status?.codigoRetorno;

    if (returnCode === 0) {
      eventServerResponse({
        content_type: 'sucesso',
        content_id: 'rewardprogram/v1/balance',
        location_1: 'monetizacao',
        location_2: 'spmais',
        location_3: 'home',
      });
      yield put(PointsActions.successPointsBalance(points));

      eventServerResponse({
        content_type: 'sucesso',
        content_id: 'rewardprogram/v1/balance',
        location_1: 'monetizacao',
        location_2: 'spmais',
        location_3: 'home',
      })
    } else {
      eventServerResponse({
        content_type: 'erro',
        content_id: 'rewardprogram/v1/balance',
        location_1: 'monetizacao',
        location_2: 'spmais',
        location_3: 'home',
      });
      yield put(PointsActions.failedPointsBalance());

      eventServerResponse({
        content_type: 'erro',
        content_id: 'rewardprogram/v1/balance',
        location_1: 'monetizacao',
        location_2: 'spmais',
        location_3: 'home',
      })
    }
  } catch (error) {
    eventServerResponse({
      content_type: 'erro',
      content_id: 'rewardprogram/v1/balance',
      location_1: 'monetizacao',
      location_2: 'spmais',
      location_3: 'home',
    });
    yield put(PointsActions.failedPointsBalance());
  }
}

